import asyncio


class SlowFetcher:
    def __init__(self, timeout=0.001):
        self.timeout = timeout

    async def slow_fetch(self):
        # simulate slow network
        await asyncio.sleep(0.5)
        return {'body': 'ok'}

    async def fetch_with_timeout(self, url):
        # BUG: 1ms timeout is too aggressive for real work
        async with asyncio.timeout(self.timeout):
            return await self.slow_fetch()


async def fetch_with_timeout(url):
    return await SlowFetcher().fetch_with_timeout(url)


async def main():
    url = 'https://example.com'
    data = await fetch_with_timeout(url)
    print(data)


if __name__ == '__main__':
    asyncio.run(main())
